CREATE OR REPLACE FUNCTION sync_module_crf_version_to_crf_version()
RETURNS TRIGGER AS $$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO crf_version (
            crf_version_id, crf_id, name, description, revision_notes,
            oc_oid, status_id, owner_id, date_created, date_updated, update_id
        )
        VALUES (
            NEW.crf_version_id, NEW.crf_id, NEW.name, NEW.description, NEW.revision_notes,
            NEW.oc_oid, NEW.status_id, NEW.owner_id, NEW.date_created, NEW.date_updated, NEW.update_id
        );
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE crf_version SET
            crf_id = NEW.crf_id,
            name = NEW.name,
            description = NEW.description,
            revision_notes = NEW.revision_notes,
            oc_oid = NEW.oc_oid,
            status_id = NEW.status_id,
            owner_id = NEW.owner_id,
            date_created = NEW.date_created,
            date_updated = NEW.date_updated,
            update_id = NEW.update_id
        WHERE crf_version_id = OLD.crf_version_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM crf_version WHERE crf_version_id = OLD.crf_version_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sync_module_crf_version
AFTER INSERT OR UPDATE OR DELETE ON module_crf_version
FOR EACH ROW EXECUTE FUNCTION sync_module_crf_version_to_crf_version();
